from flask import Flask, request, jsonify
from flask_oauthlib import OAuth, client_manager,callback_handler
from sqlalchemy import create_engine, MetaData, Table, select
import datetime

app = Flask(__name__)
oauth = OAuth(app)

# OAuth 2.0 client configuration
GOOGLE = oauth.remote_app('google',
                           consumer_key='YOUR_CONSUMER_KEY',
                           consumer_secret='YOUR_CONSUMER_SECRET',
                           request_token_params={ 'scope': 'email' })

# Database connection and token table creation
engine = create_engine('sqlite:///tokens.db')
metadata = MetaData()
tokens = Table('tokens', metadata,
                autoload_with=engine)

@app.before_request
def before_request():
    if request.endpoint != 'oauth.authorized':
        access_token = request.args.get('access_token')
        if not access_token:
            return jsonify({"error": "Missing access token"}), 401

        try:
            result = engine.execute(select([tokens.c.id, tokens.c.access_token]).where(tokens.c.access_token == access_token)).fetchone()
        except Exception as e:
            return jsonify({"error": "Database error"}), 500

        if not result:
            return jsonify({"error": "Invalid token"}), 401

@app.route('/oauth/callback')
def callback():
    callback_handler(request)
    return app.send_static_file('index.html')

@app.route('/api/protected')
@GOOGLE.login_required
def protected():
    userinfo = GOOGLE.get('userinfo')
    return jsonify({'username': userinfo['email']})

